#!/usr/bin/env python3
"""Apply script: League History Context v1 — cross-season longitudinal derivation.

Adds the longitudinal engine layer that computes all-time records,
head-to-head history, scoring records, and streaks across all seasons.

Files:
- src/squadvault/core/recaps/context/league_history_v1.py (NEW)
- src/squadvault/core/recaps/context/season_context_v1.py (docstring fixes)
- Tests/test_league_history_v1.py (NEW — 21 tests)

Usage (from repo root):
    python scripts/apply_league_history_v1.py

Verified against: 1051 passed, 3 skipped
"""
import base64
import json
import os
import sys
from pathlib import Path

MANIFEST = json.loads("""{"src/squadvault/core/recaps/context/season_context_v1.py": "", "src/squadvault/core/recaps/context/league_history_v1.py": "", "Tests/test_league_history_v1.py": ""}""")

def _find_repo_root() -> Path:
    script_dir = Path(__file__).resolve().parent
    if script_dir.name == "scripts" and (script_dir.parent / "src" / "squadvault").is_dir():
        return script_dir.parent
    cwd = Path.cwd()
    if (cwd / "src" / "squadvault").is_dir():
        return cwd
    return None

def main():
    repo_root = _find_repo_root()
    if repo_root is None:
        print("ERROR: Cannot find src/squadvault/")
        sys.exit(1)

    print(f"Repo root: {repo_root}")
    print(f"Applying League History Context v1 (3 files)...")
    print()

    for rel_path, b64_content in MANIFEST.items():
        target = repo_root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content)} bytes)")

    print()
    print("All files written. Run:")
    print("  PYTHONPATH=src python -m pytest Tests/test_league_history_v1.py -v")
    print("  PYTHONPATH=src python -m pytest Tests/ -q")

if __name__ == "__main__":
    main()
